request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?origId ?normId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "985f88f59e8b4962a0a2c2fec001b6d1" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:originalId ?origId ;
         tai:normalizedId ?normId .

  {
    ?model bbo:name ?modelName2 .
    FILTER(CONTAINS(LCASE(STR(?modelName2)), "restaurant") || CONTAINS(LCASE(STR(?modelName2)), "food") || CONTAINS(LCASE(STR(?modelName2)), "order"))
  }
  UNION
  {
    ?defs tai:belongsTo ?model .
    ?elem bbo:name ?elemName .
    FILTER(
      CONTAINS(LCASE(STR(?elemName)), "restaurant") ||
      CONTAINS(LCASE(STR(?elemName)), "food") ||
      CONTAINS(LCASE(STR(?elemName)), "order")
    )
    FILTER( ?defs = ?elem || EXISTS { ?elem tai:belongsTo ?choreo . ?choreo tai:belongsTo ?defs } )
  }
}
ORDER BY DESC(?created)
LIMIT 25
